type UserDto = {
  id: string
  first_name: string
  last_name: string
}

type User = {
  id: string
  fullName: string
}

const mapUser = (dto: UserDto): User => {
  return {
    id: dto.id,
    fullName: [dto.first_name, dto.last_name].join(" "),
  }
}

